INSERT INTO `IELTSExam` (`id`, `title`, `type`, `isFullExam`, `difficultyLevel`, `totalQuestions`, `totalSections`, `durationMinutes`, `isPublished`, `createdAt`, `updatedAt`)
INSERT INTO `IELTSExamSection` (`id`, `examId`, `sectionIndex`, `title`, `instructions`, `createdAt`) VALUES
(410, 40, 1, 'Passage 1: Georgia O''Keeffe',
INSERT INTO `IELTSQuestion` (`sectionId`, `questionIndex`, `questionType`, `questionText`, `options`, `correctAnswer`, `score`, `answerExplanation`, `createdAt`) VALUES
(410, 1, 'fill_blank', 'Before becoming a full-time artist, O''Keeffe worked as a(n) ______.', NULL, 'teacher', 1.0, '"initially worked as a teacher while continuing to develop her own artistic style."', NOW()),
(410, 2, 'fill_blank', 'Stieglitz exhibited O''Keeffe''s ______ drawings without her permission in 1916.', NULL, 'charcoal', 1.0, '"exhibited a series of her charcoal drawings at his gallery."', NOW()),
(410, 3, 'fill_blank', 'In New York, O''Keeffe painted ______, capturing the energy of modern urban life.', NULL, 'skyscrapers', 1.0, '"became captivated by the skyscrapers of New York City."', NOW()),
(410, 4, 'fill_blank', 'O''Keeffe is most famous for her large-scale paintings of ______.', NULL, 'flowers', 1.0, '"creating the large-scale paintings of flowers for which she would become most famous."', NOW()),
(410, 5, 'fill_blank', 'In New Mexico, O''Keeffe was fascinated by ______ found across the desert.', NULL, 'bones', 1.0, '"deeply fascinated by the bones she found scattered across the desert."', NOW()),
(410, 6, 'fill_blank', 'The New Mexico desert ______ is said to have inspired many of O''Keeffe''s greatest works.', NULL, 'landscape', 1.0, '"the landscape there would come to define the rest of her artistic career."', NOW()),
(410, 7, 'fill_blank', 'O''Keeffe painted dramatic rock formations under the clear light of the region''s ______ valley.', NULL, 'rivers', 1.0, 'The landscape included dramatic rock formations and rivers.', NOW()),
(410, 8, 'true_false', 'O''Keeffe studied art at the Art Institute of Chicago before becoming an artist.', NULL, 'TRUE', 1.0, '"studying at the Art Institute of Chicago."', NOW()),
(410, 9, 'true_false', 'Stieglitz''s exhibition of O''Keeffe''s work led to their marriage.', NULL, 'TRUE', 1.0, '"a relationship began that would shape both of their lives — they later married."', NOW()),
(410, 10, 'true_false', 'O''Keeffe''s flower paintings were immediately popular with critics.', NULL, 'FALSE', 1.0, 'The text describes them as "unlike anything seen before" without stating immediate popularity.', NOW()),
(410, 11, 'true_false', 'O''Keeffe moved permanently to New Mexico during her lifetime.', NULL, 'TRUE', 1.0, '"She spent her final years in Santa Fe, New Mexico."', NOW()),
(410, 12, 'true_false', 'O''Keeffe''s eyesight failure in the 1970s led her to abandon painting completely.', NULL, 'FALSE', 1.0, '"she continued to create art with the help of assistants."', NOW()),
(410, 13, 'true_false', 'O''Keeffe learned to paint from other artists in New Mexico.', NULL, 'NOT GIVEN', 1.0, 'No mention of learning from other artists in New Mexico.', NOW());
INSERT INTO `IELTSExamSection` (`id`, `examId`, `sectionIndex`, `title`, `instructions`, `createdAt`) VALUES
(420, 40, 2, 'Passage 2: Adapting to the Effects of Climate Change',
INSERT INTO `IELTSQuestion` (`sectionId`, `questionIndex`, `questionType`, `questionText`, `options`, `correctAnswer`, `score`, `answerExplanation`, `createdAt`) VALUES
(420, 14, 'multiple_choice', 'Which paragraph describes how mangroves function as natural protection for coastlines?', '["A","B","C","D","E","F"]', 'C', 1.0, 'Para C explains mangrove roots trap sediment and dampen waves.', NOW()),
(420, 15, 'multiple_choice', 'Which paragraph contains a prediction that global warming would continue for around 40 years?', '["A","B","C","D","E","F"]', 'A', 1.0, '"global warming would continue for around 40 years."', NOW()),
(420, 16, 'multiple_choice', 'Which paragraph notes that floating houses cost about one-third as much as permanent elevation?', '["A","B","C","D","E","F"]', 'D', 1.0, '"about a third of what it would cost to completely replace a building''s foundations."', NOW()),
(420, 17, 'multiple_choice', 'Which paragraph describes a GIS mapping tool used to identify areas needing intervention?', '["A","B","C","D","E","F"]', 'F', 1.0, '"Using a Geographic Information System data mapping tool."', NOW());
INSERT INTO `IELTSQuestion` (`sectionId`, `questionIndex`, `questionType`, `questionText`, `options`, `correctAnswer`, `score`, `answerExplanation`, `createdAt`) VALUES
(420, 18, 'fill_blank', 'In Miami Beach, new ______ can remove up to 75,000 litres of water per minute.', NULL, 'pumps', 1.0, '"set up new pumps that can remove up to 75,000 litres of water per minute."', NOW()),
(420, 19, 'fill_blank', 'In Java, semi-permeable ______ made of bamboo and brushwood were built to mimic mangrove roots.', NULL, 'dams', 1.0, '"building semi-permeable dams, made from bamboo poles and brushwood."', NOW()),
(420, 20, 'fill_blank', 'In Vietnam''s Mekong Delta, houses were built to ______ when floodwaters rise.', NULL, 'float', 1.0, '"these ones had been built to float."', NOW()),
(420, 21, 'fill_blank', 'In Bangladesh, farmers are learning to cultivate salt-tolerant ______.', NULL, 'crops', 1.0, '"start cultivating naturally salt-tolerant crops."', NOW()),
(420, 22, 'fill_blank', 'In Los Angeles, the Cool Streets programme includes planting ______.', NULL, 'trees', 1.0, '"include the planting of trees."', NOW());
INSERT INTO `IELTSQuestion` (`sectionId`, `questionIndex`, `questionType`, `questionText`, `options`, `correctAnswer`, `score`, `answerExplanation`, `createdAt`) VALUES
(420, 23, 'multiple_choice', 'Who said multifunctional approaches engaging communities are critical for long-term success?', '["Yanira Pineda","Susanna Tol","Elizabeth English","Raisa Chowdhury","Greg Spotts"]', 'Susanna Tol', 1.0, 'Tol: "critical that we transition towards multifunctional approaches."', NOW()),
(420, 24, 'multiple_choice', 'Who said urban cooling is literally a matter of life and death?', '["Yanira Pineda","Susanna Tol","Elizabeth English","Raisa Chowdhury","Greg Spotts"]', 'Greg Spotts', 1.0, '"Urban cooling is literally a matter of life and death for our future in LA."', NOW()),
(420, 25, 'multiple_choice', 'Who said more work will be needed in the coming decades to deal with rising water?', '["Yanira Pineda","Susanna Tol","Elizabeth English","Raisa Chowdhury","Greg Spotts"]', 'Yanira Pineda', 1.0, '"We know that in 20, 30, 40 years, we''ll need to go back."', NOW()),
(420, 26, 'multiple_choice', 'Who said their technology is becoming necessary in places that did not previously need it?', '["Yanira Pineda","Susanna Tol","Elizabeth English","Raisa Chowdhury","Greg Spotts"]', 'Elizabeth English', 1.0, '"this technology is becoming necessary in places that didn''t previously need it."', NOW());
INSERT INTO `IELTSExamSection` (`id`, `examId`, `sectionIndex`, `title`, `instructions`, `createdAt`) VALUES
(430, 40, 3, 'Passage 3: A New Role for Livestock Guard Dogs',
INSERT INTO `IELTSQuestion` (`sectionId`, `questionIndex`, `questionType`, `questionText`, `options`, `correctAnswer`, `score`, `answerExplanation`, `createdAt`) VALUES
(430, 27, 'multiple_choice', 'Which paragraph describes guard dogs protecting cheetahs in Namibia?', '["A","B","C","D","E","F","G"]', 'D', 1.0, '"the use of guard dogs in Namibia, where they are used to protect cattle from cheetahs."', NOW()),
(430, 28, 'multiple_choice', 'Which paragraph mentions a bright future for guard dogs in conservation?', '["A","B","C","D","E","F","G"]', 'G', 1.0, '"many conservationists see a bright future for guard dogs."', NOW()),
(430, 29, 'multiple_choice', 'Which paragraph explains that guard dogs physically position themselves between livestock and danger?', '["A","B","C","D","E","F","G"]', 'A', 1.0, '"placing themselves between the livestock and any perceived threat."', NOW()),
(430, 30, 'multiple_choice', 'Which paragraph provides specific numerical evidence of guard dog effectiveness?', '["A","B","C","D","E","F","G"]', 'B', 1.0, 'Ribeiro: ~90% reduction; Van Bommel/Johnson: 65% reduction.', NOW()),
(430, 31, 'multiple_choice', 'Which paragraph mentions that guard dogs are raised from an early age with livestock?', '["A","B","C","D","E","F","G"]', 'A', 1.0, '"raised from an early age with the animals they are meant to protect."', NOW()),
(430, 32, 'multiple_choice', 'Who describes guard dogs as creating a win-win situation for livestock and wildlife?', '["Dan Macon","Silvia Ribeiro","Linda van Bommel","Julie Young","Bethany Smith"]', 'Julie Young', 1.0, '"a ''win-win'' situation that saves both livestock and wild animals."', NOW()),
(430, 33, 'multiple_choice', 'Who says reported success rates should be taken with a pinch of salt?', '["Dan Macon","Silvia Ribeiro","Linda van Bommel","Julie Young","Bethany Smith"]', 'Bethany Smith', 1.0, '"should be ''taken with a pinch of salt'' because data comes from farmers."', NOW()),
(430, 34, 'multiple_choice', 'Who notes that wolf pressure may transfer to neighbouring farms without dogs?', '["Dan Macon","Silvia Ribeiro","Linda van Bommel","Julie Young","Bethany Smith"]', 'Silvia Ribeiro', 1.0, '"wolf pressure is simply transferred to neighbouring farms."', NOW()),
(430, 35, 'multiple_choice', 'Who describes guard dogs as the most efficient control method for protecting livestock?', '["Dan Macon","Silvia Ribeiro","Linda van Bommel","Julie Young","Bethany Smith"]', 'Linda van Bommel', 1.0, '"the most efficient control method for protecting livestock from predators."', NOW()),
(430, 36, 'multiple_choice', 'Who explains that livestock guard dogs have a different focus compared to house guard dogs?', '["Dan Macon","Silvia Ribeiro","Linda van Bommel","Julie Young","Bethany Smith"]', 'Dan Macon', 1.0, '"a different focus compared to house guard dogs."', NOW()),
(430, 37, 'fill_blank', 'Research in Namibia showed that ______ deaths increased when guard dogs were introduced.', NULL, 'jackals', 1.0, '"jackal deaths increased as jackals turned to other prey."', NOW()),
(430, 38, 'fill_blank', 'Guard dogs can potentially spread ______ to wild animals.', NULL, 'diseases', 1.0, '"dogs can spread diseases to wild animals."', NOW()),
(430, 39, 'fill_blank', 'Guard dogs may compete with native carnivores for ______.', NULL, 'food', 1.0, '"compete with native carnivores for food."', NOW()),
(430, 40, 'fill_blank', 'Guard dogs have been found to protect ground-nesting birds from ______.', NULL, 'foxes', 1.0, '"protect ground-nesting birds from foxes."', NOW());
